1	/**
2	 * YOU PROBABLY DON'T NEED TO EDIT THIS FILE, UNLESS:
3	 * 1. You want to modify request context (see Part 1)
4	 * 2. You want to create a new middleware or type of procedure (see Part 3)
5	 *
6	 * tl;dr - this is where all the tRPC server stuff is created and plugged in.
7	 * The pieces you will need to use are documented accordingly near the end
8	 */
9	
10	import { db } from "@db/app/client";
11	import { getCachedUserOrgMemberships } from "@repo/app-clerk-cache";
12	import { initTRPC, TRPCError } from "@trpc/server";
13	import { auth } from "@vendor/clerk/server";
14	import { createObservabilityMiddleware } from "@vendor/observability/trpc";
15	import superjson from "superjson";
16	import { ZodError } from "zod";
17	
18	/**
19	 * Authentication Context - Discriminated Union
20	 * Represents exactly one authentication method per request
21	 */
22	type AuthContext =
23	  | {
24	      type: "clerk-pending";
25	      userId: string;
26	      // Authenticated but hasn't claimed an organization yet
27	      // Only allowed for onboarding procedures
28	    }
29	  | {
30	      type: "clerk-active";
31	      userId: string;
32	      orgId: string;
33	      // Authenticated and has claimed an organization
34	      // Can access all org-scoped resources
35	    }
36	  | {
37	      type: "unauthenticated";
38	    };
39	
40	/**
41	 * 1. CONTEXT
42	 *
43	 * This section defines the "contexts" that are available in the backend API.
44	 *
45	 * These allow you to access things when processing a request, like the database, the session, etc.
46	 *
47	 * This helper generates the "internals" for a tRPC context. The API handler and RSC clients each
48	 * wrap this and provides the required context.
49	 *
50	 * @see https://trpc.io/docs/server/context
51	 */
52	
53	/**
54	 * Unified tRPC context factory (Clerk auth only)
55	 *
56	 * API key auth is handled by the REST layer (withApiKeyAuth, withDualAuth),
57	 * not tRPC. The CLI uses REST endpoints, not tRPC procedures.
58	 */
59	export const createTRPCContext = async (opts: { headers: Headers }) => {
60	  const clerkSession = await auth({ treatPendingAsSignedOut: false });
61	
62	  if (clerkSession.userId) {
63	    if (clerkSession.orgId) {
64	      return {
65	        auth: {
66	          type: "clerk-active" as const,
67	          userId: clerkSession.userId,
68	          orgId: clerkSession.orgId,
69	        },
70	        db,
71	        headers: opts.headers,
72	      };
73	    }
74	    return {
75	      auth: {
76	        type: "clerk-pending" as const,
77	        userId: clerkSession.userId,
78	      },
79	      db,
80	      headers: opts.headers,
81	    };
82	  }
83	
84	  return {
85	    auth: { type: "unauthenticated" as const },
86	    db,
87	    headers: opts.headers,
88	  };
89	};
90	
91	/**
92	 * 2. INITIALIZATION
93	 *
94	 * This is where the trpc api is initialized, connecting the context and
95	 * transformer
96	 *
97	 * Uses the unified createTRPCContext factory (Clerk auth only).
98	 */
99	const isProduction = process.env.NODE_ENV === "production";
100	
101	const t = initTRPC.context<typeof createTRPCContext>().create({
102	  transformer: superjson,
103	  errorFormatter: ({ shape, error }) => {
104	    // In production, sanitize INTERNAL_SERVER_ERROR messages to prevent credential leaks.
105	    // Procedures that throw TRPCError with specific codes (CONFLICT, BAD_REQUEST, etc.)
106	    // intentionally set user-facing messages, so those are preserved.
107	    const shouldSanitize =
108	      isProduction && error.code === "INTERNAL_SERVER_ERROR";
109	
110	    return {
111	      ...shape,
112	      message: shouldSanitize ? "An unexpected error occurred" : shape.message,
113	      data: {
114	        ...shape.data,
115	        zodError:
116	          error.cause instanceof ZodError ? error.cause.flatten() : null,
117	      },
118	    };
119	  },
120	});
121	
122	/**
123	 * 3. ROUTER & PROCEDURE (THE IMPORTANT BIT)
124	 *
125	 * These are the pieces you use to build your tRPC API. You should import these
126	 * a lot in the /src/server/api/routers folder
127	 */
128	
129	/**
130	 * This is how you create new routers and subrouters in your tRPC API
131	 * @see https://trpc.io/docs/router
132	 */
133	export const createTRPCRouter = t.router;
134	
135	/**
136	 * Create a server-side caller
137	 * @see https://trpc.io/docs/server/server-side-calls
138	 */
139	export const createCallerFactory = t.createCallerFactory;
140	
141	/**
142	 * Middleware for timing procedure execution and adding an artificial delay in development.
143	 *
144	 * You can remove this if you don't like it, but it can help catch unwanted waterfalls by simulating
145	 * network latency that would occur in production but not in local development.
146	 */
147	const observabilityMiddleware = t.middleware(
148	  createObservabilityMiddleware({
149	    isDev: t._config.isDev,
150	    extractAuth: (ctx) => ({
151	      ...(ctx.auth.type === "clerk-active" && {
152	        userId: ctx.auth.userId,
153	        orgId: ctx.auth.orgId,
154	      }),
155	      ...(ctx.auth.type === "clerk-pending" && {
156	        userId: ctx.auth.userId,
157	      }),
158	    }),
159	  })
160	);
161	
162	/**
163	 * Public (unauthed) procedure
164	 *
165	 * This is the base piece you use to build new queries and mutations on your
166	 * tRPC API. It does not guarantee that a user querying is authorized, but you
167	 * can still access user session data if they are logged in
168	 */
169	export const publicProcedure = t.procedure.use(observabilityMiddleware);
170	
171	/**
172	 * User-Scoped Procedure
173	 *
174	 * For user-level operations: account settings, profile, list orgs, create org.
175	 * Accepts both clerk-pending (no org) and clerk-active (has org) users.
176	 *
177	 * Use cases:
178	 * - User profile and settings
179	 * - List user's organizations
180	 * - Create new organization
181	 * - User-level integrations (GitHub account connection)
182	 *
183	 * For org-scoped operations (repos, integrations), use `orgScopedProcedure`.
184	 *
185	 * @see https://trpc.io/docs/procedures
186	 */
187	export const userScopedProcedure = t.procedure
188	  .use(observabilityMiddleware)
189	  .use(({ ctx, next }) => {
190	    if (ctx.auth.type === "unauthenticated") {
191	      throw new TRPCError({
192	        code: "UNAUTHORIZED",
193	        message: "Authentication required. Please sign in.",
194	      });
195	    }
196	
197	    // Allow both clerk-pending and clerk-active
198	    if (ctx.auth.type !== "clerk-pending" && ctx.auth.type !== "clerk-active") {
199	      throw new TRPCError({
200	        code: "UNAUTHORIZED",
201	        message: "Clerk authentication required",
202	      });
203	    }
204	
205	    return next({
206	      ctx: {
207	        ...ctx,
208	        // Type-safe: either clerk-pending or clerk-active
209	        auth: ctx.auth as Extract<
210	          AuthContext,
211	          { type: "clerk-pending" | "clerk-active" }
212	        >,
213	      },
214	    });
215	  });
216	
217	/**
218	 * Org-Scoped Procedure
219	 *
220	 * For org-level operations: repositories, members, integrations.
221	 * Only accepts clerk-active users (authenticated + has claimed org).
222	 *
223	 * Type-safe: `ctx.auth.orgId` is guaranteed to exist.
224	 *
225	 * Use cases:
226	 * - Repositories (connect, sync)
227	 * - Org members (invite, remove)
228	 * - Org integrations (GitHub org, Slack)
229	 * - Org settings
230	 *
231	 * For user-level operations (profile, create org), use `userScopedProcedure`.
232	 *
233	 * @see https://trpc.io/docs/procedures
234	 */
235	export const orgScopedProcedure = t.procedure
236	  .use(observabilityMiddleware)
237	  .use(({ ctx, next }) => {
238	    if (ctx.auth.type === "unauthenticated") {
239	      throw new TRPCError({
240	        code: "UNAUTHORIZED",
241	        message: "Authentication required. Please sign in.",
242	      });
243	    }
244	
245	    // Only allow clerk-active (has org)
246	    if (ctx.auth.type !== "clerk-active") {
247	      throw new TRPCError({
248	        code: "FORBIDDEN",
249	        message:
250	          "Organization required. Please create or join an organization first.",
251	      });
252	    }
253	
254	    return next({
255	      ctx: {
256	        ...ctx,
257	        // Type-safe: orgId is guaranteed to exist
258	        auth: ctx.auth as Extract<AuthContext, { type: "clerk-active" }>,
259	      },
260	    });
261	  });
262	
263	/**
264	 * Helper: Verify organization membership
265	 *
266	 * Strategy: User-centric lookup with caching - fetches user's orgs (typically 1-5)
267	 * instead of org's members (could be 100+). This is O(user_orgs) vs O(org_size).
268	 *
269	 * This centralizes the pattern of:
270	 * 1. Fetching user's organization memberships (cached)
271	 * 2. Verifying user has access to the organization
272	 * 3. Optionally verifying user has admin role
273	 * 4. Returning the membership object for further processing
274	 *
275	 * Use this in procedures that need to verify organization-level access
276	 * (organization settings, member management, etc.)
277	 *
278	 * @throws {TRPCError} FORBIDDEN if user doesn't have access or doesn't have required role
279	 */
280	export async function verifyOrgMembership(params: {
281	  clerkOrgId: string;
282	  userId: string;
283	  requireAdmin?: boolean;
284	}): Promise<{
285	  role: string;
286	  organization: {
287	    id: string;
288	    name: string;
289	    slug: string | null;
290	    imageUrl: string;
291	  };
292	}> {
293	  // User-centric lookup: get user's orgs (cached)
294	  const userMemberships = await getCachedUserOrgMemberships(params.userId);
295	
296	  // Find membership in target org
297	  const userMembership = userMemberships.find(
298	    (m) => m.organizationId === params.clerkOrgId
299	  );
300	
301	  if (!userMembership) {
302	    throw new TRPCError({
303	      code: "FORBIDDEN",
304	      message: "Access denied to this organization",
305	    });
306	  }
307	
308	  // Check admin requirement if specified
309	  if (params.requireAdmin && userMembership.role !== "org:admin") {
310	    throw new TRPCError({
311	      code: "FORBIDDEN",
312	      message: "Only administrators can perform this action",
313	    });
314	  }
315	
316	  return {
317	    role: userMembership.role,
318	    organization: {
319	      id: userMembership.organizationId,
320	      name: userMembership.organizationName,
321	      slug: userMembership.organizationSlug,
322	      imageUrl: userMembership.imageUrl,
323	    },
324	  };
325	}
